  const [data, setData] = useState<DashboardData>();

  useEffect(() => {
    fetchDashboardData().then(setData);
  }, []);

  return (
    <div>
      <h1>Dashboard</h1>
      <div className="metrics">
        {data.metrics.map(m => (
